// Filter settlement reports to only unprocessed ones
const cursorItems = $('Read Cursor').all();
const cursorRow = cursorItems.length > 0 ? cursorItems[0].json : {};
const cursorData = cursorRow.metadata || {};
const processedIds = new Set(cursorData.processedReportIds || []);

const reportsResponse = $('List Settlement Reports').first().json;
const allReports = reportsResponse.reports || [];

const newReports = allReports
  .filter(r => r.reportDocumentId && !processedIds.has(r.reportId))
  .sort((a, b) => (a.createdTime || '').localeCompare(b.createdTime || ''));

if (newReports.length === 0) {
  return [];
}

// Max 5 reports per run to respect rate limits
return newReports.slice(0, 5).map(r => ({ json: r }));

// Parse settlement TSV and map to channel_fees records
const CHANNEL_ID = '7f84462f-86c8-4e09-abb6-285631db0d83';

// Get downloaded report text
const downloadResult = $input.first();
const text = typeof downloadResult.json === 'string'
  ? downloadResult.json
  : downloadResult.json.data || downloadResult.json.body || '';

const reportId = $('Loop Over Reports').first().json.reportId;

if (!text || text.length < 10) {
  return [{ json: { fees: [], feesJson: '[]', count: 0, reportId } }];
}

// Build order map from upstream Supabase query
const orderItems = $('Get Amazon Orders').all();
const orderMap = {};
for (const item of orderItems) {
  if (item.json.order_number && item.json.id) {
    orderMap[item.json.order_number] = item.json.id;
  }
}

// Parse TSV
const lines = text.split('\n').filter(l => l.trim());
if (lines.length < 2) {
  return [{ json: { fees: [], feesJson: '[]', count: 0, reportId } }];
}

const headers = lines[0].split('\t').map(h => h.trim().toLowerCase().replace(/-/g, '_'));

const FEE_TYPE_MAP = {
  'Commission': 'marketplace_commission',
  'RefundCommission': 'marketplace_commission',
  'Promotion': 'promotion',
  'PromotionShipping': 'promotion',
};

const fees = [];
for (let i = 1; i < lines.length; i++) {
  const vals = lines[i].split('\t');
  const row = {};
  for (let j = 0; j < headers.length; j++) {
    row[headers[j]] = (vals[j] || '').trim();
  }

  const amountType = row.amount_type || '';
  const amountDesc = row.amount_description || '';
  const amount = parseFloat(row.amount || '0');

  if (!amountDesc || isNaN(amount) || amount === 0) continue;
  if (amountType === 'ItemPrice' && !amountDesc.includes('Tax')) continue;

  let feeType = FEE_TYPE_MAP[amountDesc] || null;
  if (!feeType) {
    if (amountType === 'ItemFees' || amountType === 'ItemWithheldTax') feeType = 'other';
    else if (amountType === 'Promotion') feeType = 'promotion';
    else if (amountType === 'OtherFees' || amountType === 'ServiceFee') feeType = 'other';
    else continue;
  }

  const orderNumber = row.order_id || '';
  const settlementId = row.settlement_id || '';
  const orderItemCode = row.order_item_code || '';
  const externalRef = `${settlementId}-${orderNumber}-${orderItemCode}-${amountDesc}`;
  const postedDate = row.posted_date || row.posted_date_time || '';

  const metadata = { settlement_id: settlementId, original_amount: amount };
  if (row.sku) metadata.sku = row.sku;
  if (row.fulfillment_id) metadata.fulfillment_id = row.fulfillment_id;
  if (orderItemCode) metadata.order_item_code = orderItemCode;
  if (row.transaction_type) metadata.transaction_type = row.transaction_type;
  if (amountType) metadata.amount_type = amountType;

  fees.push({
    channel_id: CHANNEL_ID,
    order_id: orderMap[orderNumber] || null,
    fee_type: feeType,
    description: amountDesc,
    amount: Math.abs(amount),
    currency_code: row.currency || 'USD',
    incurred_at: postedDate ? new Date(postedDate).toISOString() : null,
    external_ref: externalRef,
    metadata,
  });
}

return [{ json: { fees, feesJson: JSON.stringify(fees), count: fees.length, reportId } }];

// Build updated cursor with all processed report IDs
const cursorItems = $('Read Cursor').all();
const cursorRow = cursorItems.length > 0 ? cursorItems[0].json : {};
const existingMeta = cursorRow.metadata || {};
const existingIds = existingMeta.processedReportIds || [];

// All reports that went through the loop
const processedReports = $('Filter New Reports').all();
const newIds = processedReports.map(item => item.json.reportId).filter(Boolean);

const allIds = [...new Set([...existingIds, ...newIds])];

return [{
  json: {
    source: 'amazon_settlements',
    cursor_value: new Date().toISOString(),
    last_synced_at: new Date().toISOString(),
    records_synced: newIds.length,
    metadata: {
      processedReportIds: allIds,
      lastRun: new Date().toISOString()
    }
  }
}];
